        t.addLesson(new Lesson("1. What is an average?", "<p>The <strong>average</strong> (or <em>mean</em>) is the single \u201cfair-share\u201d value you'd get if you spread everything out equally.</p>" + Doc.formula("Average = (sum of all the values) \u00f7 (how many values)") + Doc.analogy("Three friends have 4, 8 and 6 chocolates. If they pour them into one pile (18) and redistribute equally, each gets 6. So the average is 6 \u2014 the amount everyone would have if sharing were perfectly fair.") + Doc.example("Average of 4, 8, 10 and 14", "Sum = 4+8+10+14 = 36. Count = 4. Average = 36 \u00f7 4 = <strong>9</strong>.") + Doc.key("Flip the formula whenever you know the average: <strong>Total = average \u00d7 number of values.</strong> This \u2018total\u2019 idea unlocks most average problems.") + Doc.tip("The average always lands somewhere between the smallest and largest value \u2014 never outside that range. Use this to sanity-check answers.") + Doc.recap("Average = total \u00f7 count. And total = average \u00d7 count."), 1));
