        t.addQuestion(Doc.q("A class of 30 boys averages 40 kg and 20 girls average 35 kg. The class average weight is:", List.of("37.5 kg", "38 kg", "38.5 kg", "37 kg"), 1, "Total = 30\u00d740 + 20\u00d735 = 1900; /50 = 38 kg (weighted average).", "MEDIUM"));
        String ref = Doc.reference("For more on averages and mixtures see <em>Manhattan Prep GRE Word Problems</em>, and for CAT <em>Arun Sharma \u2013 Quantitative Aptitude for the CAT</em> (averages &amp; alligation chapters) and <em>Nishit K. Sinha \u2013 Quantitative Aptitude for the CAT</em>.");
